            return new DeclarativeAgentDefinition(
                ProjectsAgentKind.Prompt,
                contentFilterConfiguration,
                additionalBinaryDataProperties: null,
                model,
                instructions,
                temperature,
                topP,
                reasoningOptions,
                tools.ToList(),
                toolChoice,
                textOptions,
                structuredInputs);
        }

